class JSONSchemaParser:
    def __init__(self, schema_json):
        self.schema = schema_json
        self._validate_schema()

    def _validate_schema(self):
        if not isinstance(self.schema, dict):
            raise ValueError("Schema must be a dictionary")

    def visualize_schema(self):
        # Simple visualization of schema structure
        print("Schema Visualization:")
        self._print_schema_structure(self.schema, 0)

    def _print_schema_structure(self, node, level):
        print(" " * level + str(node))
        for key, value in node.items():
            if isinstance(value, dict):
                self._print_schema_structure(value, level + 1)
            elif isinstance(value, list):
                print(" " * (level + 1) + "List of:")
                for item in value:
                    self._print_schema_structure(item, level + 1)
            else:
                print(" " * (level + 1) + str(value))

# Example usage
