from abc import ABC, abstractmethod
from functools import lru_cache

class CacheStrategy(ABC):
    @abstractmethod
    def apply(self, n):
        pass

class MemoizationStrategy(CacheStrategy):
    def apply(self, n):
        return self._memoize(n)

    def _memoize(self, n):
        if n <= 1:
            return n
        return self._memoize(n-1) + self._memoize(n-2)

class StrategyFactory:
    @staticmethod
    def create_strategy():
        return MemoizationStrategy()

# Usage
strategy = StrategyFactory.create_strategy()
result = strategy.apply(10)
