class TcpStateMachine:
    def __init__(self):
        self.state = 'CLOSED'
        self.transitions = {
            'CLOSED': ['LISTEN', 'SYN_SENT', 'FIN_WAIT_1', 'FIN_WAIT_2', 'TIME_WAIT'],
            'LISTEN': ['NEW_CONNECTION', 'SYN_RECEIVED', 'ACK_RECEIVED', 'FIN_RECEIVED', 'FIN_CONFIRMED'],
            'SYN_SENT': ['SYN_RECEIVED', 'ACK_RECEIVED', 'FIN_RECEIVED', 'FIN_CONFIRMED'],
            'SYN_RECEIVED': ['ACK_RECEIVED', 'FIN_RECEIVED', 'FIN_CONFIRMED'],
            'ACK_RECEIVED': ['FIN_RECEIVED', 'FIN_CONFIRMED'],
            'FIN_WAIT_1': ['FIN_RECEIVED', 'FIN_CONFIRMED'],
            'FIN_WAIT_2': ['FIN_RECEIVED', 'FIN_CONFIRMED'],
            'TIME_WAIT': ['TIME_WAIT'],
            'NEW_CONNECTION': ['ESTABLISHED'],
            'ESTABLISHED': ['CLOSED']
        }

    def transition(self, current_state):
        if current_state not in self.transitions:
            raise ValueError(f"Invalid state: {current_state}")
        next_states = self.transitions[current_state]
        return next_states

    def is_state(self, state):
        return state == self.state

    def change_state(self, new_state):
        self.state = new_state

    def get_next_states(self, current_state):
        return self.transitions.get(current_state, [])

