import random
from collections import defaultdict

class MarkovChain:
    def __init__(self, corpus):
        self.transitions = defaultdict(lambda: defaultdict(int))
        self.starts = defaultdict(int)

        for sentence in corpus:
            current = ""
            for word in sentence:
                if current:
                    self.transitions[current][word] += 1
                current = word

            self.starts[word] += 1

    def generate_text(self, length=100):
        start_word = random.choice(list(self.starts.keys()))
        current = start_word

        for _ in range(length):
            next_word = self._get_next_word(current)
            if next_word:
                current = next_word
            else:
                break

        return " ".join([self._get_word(current) for _ in range(length)])

    def _get_next_word(self, current):
        if current in self.transitions:
            return random.choice(self.transitions[current].keys())
        return None

    def _get_word(self, word):
        if word in self.starts:
            return word
        return random.choice(list(self.transitions[word].keys()))
