import numpy as np

class GradientDescentOptimizer:
    def __init__(self, learning_rate=0.01):
        self.learning_rate = learning_rate
        self.strategy = None

    def set_strategy(self, strategy):
        self.strategy = strategy

    def optimize(self, model, data, labels):
        if self.strategy is None:
            raise ValueError("Strategy not set")
        return self.strategy.optimize(model, data, labels, self.learning_rate)

class Strategy:
    def optimize(self, model, data, labels, learning_rate):
        raise NotImplementedError("Subclass must implement optimize method")

class SGDStrategy(Strategy):
    def optimize(self, model, data, labels, learning_rate):
        # Simple SGD optimization
        for i in range(len(data)):
            prediction = model(data[i])
            loss = np.mean(np.square(prediction - labels[i]))
            grad = model.grad(data[i])
            model.update(grad, learning_rate)
        return loss

class AdamStrategy(Strategy):
    def optimize(self, model, data, labels, learning_rate):
        # Simple Adam optimization
        m = np.zeros_like(data)
        v = np.zeros_like(data)
        for i in range(len(data)):
            prediction = model(data[i])
            loss = np.mean(np.square(prediction - labels[i]))
            grad = model.grad(data[i])
            m = m * learning_rate + grad
            v = v * learning_rate + grad * grad
            model.update(m, v, learning_rate)
        return loss

# Example usage
