# Trie Data Structure for Autocomplete Suggestions

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def autocomplete(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]
        return [word for word in self._traverse(node) if word.startswith(prefix)]

    def _traverse(self, node):
        results = []
        if node.is_end_of_word:
            results.append(node.word)
        for child in node.children.values():
            results.extend(self._traverse(child))
        return results

# Example usage
trie = Trie()
trie.insert("apple")
trie.insert("app")
trie.insert("application")
trie.insert("banana")
trie.insert("bat")

print(trie.autocomplete("ap"))
