from redis import Redis
from functools import lru_cache

class SecureSessionStore:
    def __init__(self, redis_host='localhost', redis_port=6379, redis_db=0):
        self.redis = Redis(host=redis_host, port=redis_port, db=redis_db)

    def set_session(self, session_id, data):
        self.redis.set(session_id, data)
        self.redis.expire(session_id, 3600)  # 1 hour expiration

    def get_session(self, session_id):
        data = self.redis.get(session_id)
        if data:
            return data.decode('utf-8')
        return None

    def delete_session(self, session_id):
        self.redis.delete(session_id)

    def is_session_valid(self, session_id):
        data = self.redis.get(session_id)
        return data is not None

# Example usage
session_store = SecureSessionStore()
session_id = "user123"
session_data = {"user": "john_doe", "token": "abc123"}
session_store.set_session(session_id, session_data)
print(session_store.get_session(session_id))  # Output: {"user": "john_doe", "token": "abc123"}
