class PluginManager:
    def __init__(self):
        self.plugins = []

    def add_plugin(self, plugin):
        self.plugins.append(plugin)

    def execute_plugins(self, content):
        for plugin in self.plugins:
            content = plugin.transform(content)
        return content

class TransformerPlugin:
    def transform(self, content):
        return f"Transformed: {content}"

class OutputFormatPlugin:
    def transform(self, content):
        return f"Output: {content}"

# Usage
manager = PluginManager()
manager.add_plugin(TransformerPlugin())
manager.add_plugin(OutputFormatPlugin())

content = "Hello, world!"
processed_content = manager.execute_plugins(content)
print(processed_content)
