	s.httpServer.Handler = http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		log.Printf("Invalid request: %s %s\n", r.Method, r.URL.Path)
		http.Error(w, "Invalid request", http.StatusBadRequest)
	})

	// Handle corrupted data
	s.httpServer.Handler = http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		log.Printf("Corrupted data: %s %s\n", r.Method, r.URL.Path)
		http.Error(w, "Corrupted data", http.StatusInternalServerError)
	})

	// Handle external API failures
	s.httpServer.Handler = http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		log.Printf("External API failure: %s %s\n", r.Method, r.URL.Path)
		http.Error(w, "External API failure", http.StatusInternalServerError)
	})

	return s
}

func (s *Service) Run() {
	log.Println("Starting microservice...")
	if err := s.httpServer.ListenAndServe(); err != nil {
		log.Fatal(err)
	}
}

func main() {
	service := NewService()
	service.Run()
}

