use std::env;
use std::io::{self, Write};
use std::collections::HashMap;

#[derive(Debug)]
struct Task {
    id: String,
    description: String,
}

#[derive(Debug)]
struct TaskManager {
    tasks: Vec<Task>,
}

impl TaskManager {
    fn new() -> Self {
        TaskManager {
            tasks: Vec::new(),
        }
    }

    fn add_task(&mut self, description: &str) {
        let id = generate_id();
        self.tasks.push(Task { id, description });
        println!("Task added with ID: {}", id);
    }

    fn complete_task(&mut self, task_id: &str) {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == task_id) {
            task.completed = true;
            println!("Task completed: {}", task_id);
        } else {
            println!("Task not found");
        }
    }

    fn list_tasks(&self) {
        if self.tasks.is_empty() {
            println!("No tasks found.");
        } else {
            for (i, task) in self.tasks.iter().enumerate() {
                println!("{}. {}", i + 1, task.id);
            }
        }
    }
}

fn generate_id() -> String {
    let mut id = String::new();
    let mut rng = rand::thread_rng();
    for _ in 0..6 {
        id.push((rng.gen_range('A' as u8..='Z') as char));
    }
    id
}

fn main() {
    let mut manager = TaskManager::new();
    let mut input = String::new();
    let mut running = true;

    loop {
        print!("> ");
        io::stdout().flush().unwrap();
        input.clear();
        io::stdin().read_line(&mut input).unwrap();

        if input.trim().is_empty() {
            continue;
        }

        let cmd: Vec<&str> = input.trim().split_whitespace().collect();
        match cmd[0] {
            "add" => {
                if cmd.len() < 2 {
                    println!("Usage: add <description>");
                    continue;
                }
                let description = cmd[1];
                manager.add_task(description);
            }
            "complete" => {
                if cmd.len() < 2 {
                    println!("Usage: complete <task_id>");
                    continue;
                }
                let task_id = cmd[1];
                manager.complete_task(task_id);
            }
            "list" => {
                manager.list_tasks();
            }
            "help" => {
                println!("Available commands:");
                println!("add <description> - Add a new task");
                println!("complete <task_id> - Complete a task");
                println!("list - List all tasks");
                println!("help - Show this help message");
                println!("version - Show version");
            }
            "version" => {
                println!("v1.0.0");
            }
            _ => {
                println!("Unknown command");
            }
        }
    }
}
