import express from 'express';
import { v4 as uuidv4 } from 'uuid';

const app = express();

// Middleware to sanitize user input
const sanitizeInput = (req: express.Request, res: express.Response, next: express.NextFunction) => {
  const { body, headers } = req;
  const sanitizedBody = {};
  const sanitizedHeaders = {};

  // Sanitize body
  for (const key in body) {
    if (body[key]) {
      sanitizedBody[key] = body[key].replace(/</g, '&lt;').replace(/>/g, '&gt;');
    }
  }

  // Sanitize headers
  for (const key in headers) {
    if (headers[key]) {
      sanitizedHeaders[key] = headers[key].replace(/</g, '&lt;').replace(/>/g, '&gt;');
    }
  }

  req.body = sanitizedBody;
  req.headers = sanitizedHeaders;

  next();
};

// Route to demonstrate protection against XSS and SQL injection
app.get('/secure', sanitizeInput, (req: express.Request, res: express.Response) => {
  const userInput = req.body.username || 'default';
  const userInput2 = req.body.password || 'default';

  // Example of SQL injection (not safe)
  const sqlQuery = `SELECT * FROM users WHERE username = '${userInput}' AND password = '${userInput2}'`;
  const sanitizedSqlQuery = sqlQuery.replace(/'/g, "'");
  res.send(`Secure route: ${sanitizedSqlQuery}`);
});

// Test route to demonstrate protection
app.get('/test', sanitizeInput, (req: express.Request, res: express.Response) => {
  const testInput = req.body.testInput || 'test';
  res.send(`Test route: ${testInput}`);
