import time
from random import random
from collections import defaultdict

class CircuitBreaker:
    def __init__(self, max_failures=5, initial_state="closed"):
        self.max_failures = max_failures
        self.state = initial_state
        self.failure_count = 0
        self.failure_rates = defaultdict(float)
        self.last_failure_time = 0

    def handle_request(self, request):
        if self.state == "open":
            return self._handle_open_state()
        if self.state == "closed":
            self._handle_closed_state()
        return True

    def _handle_closed_state(self):
        self.state = "half-open"
        self.failure_count = 0
        self.last_failure_time = time.time()

    def _handle_half_open_state(self):
        if self.failure_count >= self.max_failures:
            self.state = "open"
            self.failure_count = 0
            self.last_failure_time = time.time()
        else:
            self.failure_count += 1
            self.failure_rates[self.last_failure_time] += 1

    def _handle_open_state(self):
        # Simulate failure
        if random() < 0.1:
            self.state = "closed"
            self.failure_count = 0
            self.last_failure_time = time.time()
        else:
            self.failure_count += 1
            self.failure_rates[self.last_failure_time] += 1

    def track_failure_rate(self):
        return self.failure_rates

    def is_open(self):
        return self.state == "open"

    def reset(self):
        self.state = "closed"
        self.failure_count = 0
        self.failure_rates.clear()
        self.last_failure_time = 0
