import random
import hashlib
from collections import defaultdict

class ShardedKVStore:
    def __init__(self):
        self.shards = defaultdict(list)
        self.membership = set()
        self.virtual_nodes = 10  # Number of virtual nodes

    def _hash_key(self, key):
        return int(hashlib.md5(key.encode()).hexdigest(), 16) % self.virtual_nodes

    def _get_shard(self, key):
        return self._hash_key(key) % len(self.shards)

    def add_node(self, node_id):
        self.membership.add(node_id)
        self._rebalance()

    def remove_node(self, node_id):
        self.membership.discard(node_id)
        self._rebalance()

    def _rebalance(self):
        # Distribute data to shards
        for key in self.shards:
            shard_id = self._get_shard(key)
            self.shards[shard_id].append(key)

    def get(self, key):
        shard_id = self._get_shard(key)
        for node in self.membership:
            if node in self.shards[shard_id]:
                return self.shards[shard_id][self.membership.index(node)]
        return None

    def set(self, key, value):
        shard_id = self._get_shard(key)
        for node in self.membership:
            if node in self.shards[shard_id]:
                self.shards[shard_id][self.membership.index(node)] = value
                return
        self.shards[shard_id].append((key, value))

    def gossip(self):
        for node in self.membership:
            self._update_node(node)

    def _update_node(self, node):
        # Simulate gossip update
        new_keys = [key for key in self.shards if key not in self.membership]
        for key in new_keys:
            self.shards[self._get_shard(key)].append(key)
