from abc import ABC, abstractmethod
from typing import TypeVar, Generic, Optional

# Define the event bus
class EventBus:
    def __init__(self):
        self._events = {}

    def publish(self, event_type, data):
        self._events[event_type].append((data))

    def subscribe(self, event_type, callback):
        if event_type not in self._events:
            self._events[event_type] = []
        self._events[event_type].append(callback)

    def unsubscribe(self, event_type, callback):
        if event_type in self._events and callback in self._events[event_type]:
            self._events[event_type].remove(callback)

# Define the strategy pattern
class Renderer(ABC):
    @abstractmethod
    def render(self, data):
        pass

class QtRenderer(Renderer):
    def render(self, data):
        print(f"Rendering with Qt: {data}")

class WxPythonRenderer(Renderer):
    def render(self, data):
        print(f"Rendering with WxPython: {data}")

class TextualRenderer(Renderer):
    def render(self, data):
        print(f"Rendering with Textual: {data}")

# Define the abstract widget factory
class WidgetFactory(Generic[Renderer]):
    @abstractmethod
    def create_widget(self, data):
        pass

class PlatformSpecificWidgetFactory(WidgetFactory[Renderer]):
    def create_widget(self, data):
        if data.platform == "qt":
            return QtRenderer()
        elif data.platform == "wxpython":
            return WxPythonRenderer()
        elif data.platform == "textual":
            return TextualRenderer()
        else:
            raise ValueError("Unsupported platform")

# Define the UI component
class UIComponent:
    def __init__(self, factory: WidgetFactory[Renderer]):
        self._factory = factory
        self._data = {}

    def set_data(self, data):
        self._data = data

    def update(self):
        renderer = self._factory.create_widget(self._data)
        renderer.render(self._data)

# Example usage
if __name__ == "__main__":
    event_bus = EventBus()
    ui = UIComponent(PlatformSpecificWidgetFactory())
    ui.set_data({"platform": "qt", "data": "Example data"})
    ui.update()
    event_bus.publish("ui_update", {"platform": "qt", "data": "Example data"})
