from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, List, Optional, Any

class Rule(ABC):
    @abstractmethod
    def apply(self, context: Dict[str, Any]) -> bool:
        pass

class RuleFactory:
    @staticmethod
    def create_rule(rule_type: str, **kwargs) -> Rule:
        if rule_type == "discount":
            return DiscountRule(**kwargs)
        elif rule_type == "validation":
            return ValidationRule(**kwargs)
        else:
            raise ValueError(f"Unknown rule type: {rule_type}")

class DiscountRule(Rule):
    def __init__(self, amount: float, condition: str):
        self.amount = amount
        self.condition = condition

    def apply(self, context: Dict[str, Any]) -> bool:
        if self.condition in context:
            return float(context[self.condition]) > self.amount
        return False

class ValidationRule(Rule):
    def __init__(self, field: str, condition: str):
        self.field = field
        self.condition = condition

    def apply(self, context: Dict[str, Any]) -> bool:
        return context.get(self.field) is not None and self.condition in context[self.field]

class RuleEngine:
    def __init__(self):
        self.rules = []

    def add_rule(self, rule: Rule):
        self.rules.append(rule)

    def evaluate(self, context: Dict[str, Any]) -> List[bool]:
        results = []
        for rule in self.rules:
            results.append(rule.apply(context))
        return results

class RuleDSL:
    def __init__(self):
        self.rules = []

    def discount(self, amount: float, condition: str):
        self.rules.append(DiscountRule(amount, condition))
        return self

    def validate(self, field: str, condition: str):
        self.rules.append(ValidationRule(field, condition))
        return self

    def build(self) -> RuleEngine:
        return RuleEngine() \
            .add_rule(self.discount(10, "amount > 50")) \
            .add_rule(self.validate("name", "length > 3"))

# Usage
engine = RuleDSL().build()
context = {"amount": 60, "name": "John"}
results = engine.evaluate(context)
