package main

import (
	"bufio"
	"fmt"
	"golang.org/x/exp/rand"
	"gopkg.in/yaml.v2"
	"io"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"sort"
	"strings"
	"sync"
	"time"
)

type LogEntry struct {
	IP         string
	RequestMethod string
	URL        string
	Protocol   string
	StatusCode int
	RemoteAddr string
	Bytes      int
	TimeStamp  time.Time
}

func parseLogLine(line string) LogEntry {
	fields := strings.Fields(line)
	if len(fields) < 8 {
		return LogEntry{}
	}
	ip := fields[0]
	method := fields[1]
	url := fields[2]
	protocol := fields[3]
	statusCode := fields[4]
	remoteAddr := fields[5]
	bytes := fields[6]
	timeStampStr := fields[7]

	return LogEntry{
		IP:         ip,
		RequestMethod: method,
		URL:        url,
		Protocol:   protocol,
		StatusCode: statusCode,
		RemoteAddr: remoteAddr,
		Bytes:      bytes,
		TimeStamp:  time.Now(),
	}
}

func main() {
	// Set up logging
	logFile, err := os.Create("log_parser.log")
	if err != nil {
		log.Fatal(err)
	}
	defer logFile.Close()

	// Set up a buffer for reading from gzip file
	reader, err := os.Open("example.gz")
	if err != nil {
		log.Fatal(err)
	}
	defer reader.Close()

	// Create a gzip reader
	gzr, err := gzip.NewReader(reader)
	if err != nil {
		log.Fatal(err)
	}
	defer gzr.Close()

	// Create a bufio reader for the gzip stream
	br := bufio.NewReader(gzr)

	// Create a channel for log entries
	logEntriesChan := make(chan LogEntry, 100000)

	// Create a channel for results
	resultsChan := make(chan LogEntry, 100000)

	// Create a worker pool
	numWorkers := 4
	workers := make(chan LogEntry, numWorkers)

	// Create a sync.Mutex for thread safety
	mu := sync.Mutex{}

	// Create a channel for signal
	signalChan := make(chan os.Signal, 1)
	signalChan <- os.Signal(syscall.SIGINT)

	// Start worker goroutines
	for i := 0; i < numWorkers; i++ {
		go func() {
			for {
				line, err := br.ReadString('\n')
				if err != nil {
					break
				}
				line = strings.TrimSpace(line)
				if line == "" {
					continue
				}
				entry := parseLogLine(line)
				mu.Lock()
				workers <- entry
				mu.Unlock()
			}
		}()
	}

	// Process log entries
	for range signalChan {
		break
	}

	for i := 0; i < numWorkers; i++ {
		entry := <-workers
		resultsChan <- entry
	}

	// Output results
	for entry := range resultsChan {
		logFile.WriteString(fmt.Sprintf("%s %s %s %s %d %s %d %s %s\n",
			entry.IP, entry.RequestMethod, entry.URL, entry.Protocol,
			entry.StatusCode, entry.RemoteAddr, entry.Bytes, entry.TimeStamp.Format("2006-01-02 15:04:05"),
			entry.TimeStamp.Format("2006-01-02 15:04:05")))
	}

	// Close the log file
	logFile.Close()
}

