// Example TypeScript code for a basic JSON schema editor
// This is a simplified version and not a complete implementation

import React, { useState, useEffect } from 'react';

interface Schema {
  type: string;
  properties: {
    [key: string]: Schema;
  };
  required: string[];
  description: string;
}

const SchemaEditor: React.FC = () => {
  const [schema, setSchema] = useState<Schema>({ type: 'object', properties: {}, required: [], description: '' });
  const [error, setError] = useState<string | null>(null);
  const [undoStack, setUndoStack] = useState<string[]>([]);
  const [redoStack, setRedoStack] = useState<string[]>([]);

  const handleFieldChange = (fieldName: string, value: any) => {
    // Update schema
    setSchema(prev => ({
      ...prev,
      properties: {
        ...prev.properties,
        [fieldName]: {
          ...prev.properties[fieldName],
          type: value.type,
          description: value.description,
        }
      }
    }));
  };

  const handleUndo = () => {
    if (undoStack.length > 0) {
      const last = undoStack.pop()!;
      setRedoStack(prev => [...prev, last]);
      setSchema(JSON.parse(last));
    }
  };

  const handleRedo = () => {
    if (redoStack.length > 0) {
      const last = redoStack.pop()!;
      setUndoStack(prev => [...prev, last]);
      setSchema(JSON.parse(last));
    }
  };

  const validateSchema = () => {
    // Simple validation (placeholder)
    if (schema.type === 'object' && Object.keys(schema.properties).length === 0) {
      setError('At least one field is required');
      return false;
    }
    setError(null);
    return true;
  };

  return (
    <div>
      <h2>JSON Schema Editor</h2>
      <div>
        <label>
          Description:
          <textarea
            value={schema.description}
            onChange={(e) => setSchema({ ...schema, description: e.target.value })}
          />
        </label>
      </div>
      <div>
        <label>
          Type:
          <select
            value={schema.type}
            onChange={(e) => setSchema({ ...schema, type: e.target.value })}
          >
            <option value="object">Object</option>
            <option value="array">Array</option>
            <option value="string">String</option>
            <option value="number">Number</option>
            <option value="boolean">Boolean</option>
            <option value="null">Null</option>
          </select>
        </label>
      </div>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <div>
        <label>Properties:</label>
        {Object.entries(schema.properties).map(([key, value]) => (
          <div key={key}>
            <label>{key}</label>
            <select
              value={value.type}
              onChange={(e) => handleFieldChange(key, { ...value, type: e.target.value })}
            >
              <option value="string">String</option>
              <option value="number">Number</option>
              <option value="boolean">Boolean</option>
              <option value="null">Null</option>
              <option value="array">Array</option>
              <option value="object">Object</option>
            </select>
            {value.description && (
              <div>
                <p>Description: {value.description}</p>
                <span title={value.description}>Tooltip</span>
              </div>
            )}
          </div>
        ))}
      </div>
      <div style={{ display: 'flex', gap: '10px' }}>
        <button onClick={handleUndo}>Undo</button>
        <button onClick={handleRedo}>Redo</button>
      </div>
    </div>
  );
};

export default SchemaEditor;
