#define DATA_SIZE 1000000000 // 1 GB
#define BUFFER_SIZE 1024 * 1024 * 1024 // 1 GB

std::vector<uint8_t> data;
std::vector<uint8_t> buffer;

std::mutex mtx;

void readData() {
    std::ifstream file("input.bin", std::ios::binary);
    file.read(reinterpret_cast<char*>(data.data()), DATA_SIZE);
    file.close();
}

void writeData() {
    std::ofstream file("output.bin", std::ios::binary);
    file.write(reinterpret_cast<char*>(data.data()), DATA_SIZE);
    file.close();
}

void merge(std::vector<uint8_t>& left, std::vector<uint8_t>& right, std::vector<uint8_t>& result) {
    size_t i = 0, j = 0;
    while (i < left.size() && j < right.size()) {
        if (left[i] < right[j]) {
            result.push_back(left[i]);
            i++;
        } else {
            result.push_back(right[j]);
            j++;
        }
    }
    while (i < left.size()) {
        result.push_back(left[i]);
        i++;
    }
    while (j < right.size()) {
        result.push_back(right[j]);
        j++;
    }
}

void sortThread(int start, int end) {
    std::vector<uint8_t> temp;
    for (int i = start; i < end; i += BUFFER_SIZE) {
        std::vector<uint8_t> chunk;
        std::ifstream file("input.bin", std::ios::binary);
        file.read(reinterpret_cast<char*>(chunk.data()), BUFFER_SIZE);
        file.close();
        temp.insert(temp.end(), chunk.begin(), chunk.end());
    }
    std::vector<uint8_t> sorted;
    merge(temp, data, sorted);
    data = sorted;
}

int main() {
    readData();
    std::thread t1(sortThread, 0, BUFFER_SIZE);
    std::thread t2(sortThread, BUFFER_SIZE, 2 * BUFFER_SIZE);
    std::thread t3(sortThread, 2 * BUFFER_SIZE, 3 * BUFFER_SIZE);
    std::thread t4(sortThread, 3 * BUFFER_SIZE, 4 * BUFFER_SIZE);
    std::thread t5(sortThread, 4 * BUFFER_SIZE, 5 * BUFFER_SIZE);
    std::thread t6(sortThread, 5 * BUFFER_SIZE, 6 * BUFFER_SIZE);
    std::thread t7(sortThread, 6 * BUFFER_SIZE, 7 * BUFFER_SIZE);
    std::thread t8(sortThread, 7 * BUFFER_SIZE, 8 * BUFFER_SIZE);
    std::thread t9(sortThread, 8 * BUFFER_SIZE, 9 * BUFFER_SIZE);
    std::thread t10(sortThread, 9 * BUFFER_SIZE, 10 * BUFFER_SIZE);

    t1.join();
    t2.join();
    t3.join();
    t4.join();
    t5.join();
    t6.join();
    t7.join();
    t8.join();
    t9.join();
    t10.join();

    writeData();
    return 0;
}

