	s.leader = &Node{ID: 1, State: "follower", LastIndex: 0, LastTerm: 0, Heartbeat: 0, Network: []int{1}}
	s.log = &Log{Entries: []string{}}
	s.commitIndex = 0
	s.term = 0
	s.heartbeat = 0
	s.alive = true
}

func (s *Simulation) addLogEntry(entry string) {
	s.log.Entries = append(s.log.Entries, entry)
}

func (s *Simulation) simulate() {
	for {
		s.tick()
		if !s.alive {
			break
		}
	}
}

func (s *Simulation) tick() {
	s.heartbeat++
	if s.heartbeat > 5 {
		s.heartbeat = 0
		s.alive = false
	}
}

