#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <immintrin.h>
#include <time.h>

#define SIZE 1000000
#define NUM_THREADS 4

// FFT using SIMD intrinsics
void fft_simd(float *input, float *output, int n) {
    for (int i = 0; i < n; i += 4) {
        float a = input[i];
        float b = input[i + 1];
        float c = input[i + 2];
        float d = input[i + 3];

        float temp1 = a + c;
        float temp2 = b - d;
        float temp3 = a - c;
        float temp4 = b + d;

        output[i] = temp1 + temp3;
        output[i + 1] = temp2 + temp4;
        output[i + 2] = temp1 - temp3;
        output[i + 3] = temp2 - temp4;
    }
}

// FFTW-style FFT
void fft_fftw(float *input, float *output, int n) {
    // FFTW implementation (simplified for demonstration)
    for (int i = 0; i < n; i++) {
        output[i] = 0.0f;
        for (int k = 0; k < n; k++) {
            output[i] += input[k] * cosf((2 * M_PI * i) / n) * cosf((2 * M_PI * k) / n);
        }
    }
}

// Measure CPU cycle counts
unsigned long long get_cycle_count(void) {
    unsigned long long count;
    __asm__ __volatile__("rdtsc" : "=a" (count));
    return count;
}

// Main function
int main() {
    float *input = (float *)malloc(SIZE * sizeof(float));
    float *output = (float *)malloc(SIZE * sizeof(float));

    // Initialize input
    for (int i = 0; i < SIZE; i++) {
        input[i] = sinf(2 * M_PI * i / SIZE);
    }

    // Measure time for SIMD FFT
    unsigned long long start_simd = get_cycle_count();
    fft_simd(input, output, SIZE);
    unsigned long long end_simd = get_cycle_count();
    unsigned long long simd_time = end_simd - start_simd;

    // Measure time for FFTW-style FFT
    unsigned long long start_fftw = get_cycle_count();
    fft_fftw(input, output, SIZE);
    unsigned long long end_fftw = get_cycle_count();
    unsigned long long fftw_time = end_fftw - start_fftw;

    // Output results
    printf("SIMD FFT: %lu cycles, %lu ms\n", simd_time, simd_time / 1e6);
    printf("FFTW FFT: %lu cycles, %lu ms\n", fftw_time, fftw_time / 1e6);

    free(input);
    free(output);
    return 0;
}

