        return self.hash_function(data)

    def get_nearest_neighbors(self, query):
        # Validate input
        if not isinstance(query, str):
            raise ValueError("Query must be a string")
        if not query:
            raise ValueError("Query cannot be empty")

        # Rate limiting
        current_time = time.time()
        if current_time - self.rate_limit_time > 1:
            self.rate_limit = 0
            self.rate_limit_time = current_time

        self.rate_limit += 1
        if self.rate_limit > self.max_hash_attempts:
            raise Exception("Rate limit exceeded")

        # Hash the query
        hashed_query = self.hash_data(query)
        self.hash_cache.add(hashed_query)

