std::vector<Point> convexHull(const std::vector<Point>& points) {
    // Sort points by x, then y
    std::sort(points.begin(), points.end());
    std::vector<Point> lower, upper;
    for (auto it = points.begin(); it != points.end(); ++it) {
        if (it->x == points[0].x && it->y == points[0].y) continue;
        lower.push_back(*it);
    }
    for (auto it = points.rbegin(); it != points.rend(); ++it) {
        if (it->x == points.back().x && it->y == points.back().y) continue;
        upper.push_back(*it);
    }
    // Remove duplicates
    lower.erase(std::unique(lower.begin(), lower.end()), lower.end());
    upper.erase(std::unique(upper.begin(), upper.end()), upper.end());
    // Compute convex hull
    if (lower.size() == 0 || upper.size() == 0) return {};
    std::vector<Point> result;
    for (auto it = lower.begin(); it != lower.end(); ++it) {
        result.push_back(*it);
