#include <mutex>
#include <vector>
#include <atomic>
#include <thread>
#include <chrono>
#include <iostream>

// Lock-free data structure for order matching
class OrderBook {
public:
    using Order = struct {
        int id;
        bool is_buy;
        int price;
        int quantity;
    };

    OrderBook() : orders() {}

    void addOrder(const Order& order) {
        std::lock_guard<std::mutex> lock(mutex);
        orders.push_back(order);
    }

    void removeOrder(int id) {
        std::lock_guard<std::mutex> lock(mutex);
        auto it = std::find_if(orders.begin(), orders.end(), [id](const Order& o) { return o.id == id; });
        if (it != orders.end()) {
            orders.erase(it);
        }
    }

    std::vector<Order> getOrders() const {
        std::lock_guard<std::mutex> lock(mutex);
        return orders;
    }

private:
    std::vector<Order> orders;
    std::mutex mutex;
};

// CPU affinity function
void setCPUAffinity(int cpu) {
    std::thread t([]() {
        std::atomic<int> cpu_id(0);
        while (true) {
            cpu_id.store(cpu, std::memory_order_release);
            std::this_thread::sleep_for(std::chrono::microseconds(1));
        }
    });
    t.join();
}

// Benchmark function
void benchmark(int num_threads, int num_orders) {
    std::vector<std::thread> threads;
    std::vector<OrderBook> order_books(num_threads);

    for (int i = 0; i < num_threads; ++i) {
        threads.emplace_back([i, &order_books, num_orders]() {
            for (int j = 0; j < num_orders; ++j) {
                OrderBook& book = order_books[i];
                Order order = {j, true, 100, 1};
                book.addOrder(order);
            }
        });
    }

    for (auto& thread : threads) {
        thread.join();
    }
}

// Main function
int main() {
    int num_threads = 4;
    int num_orders = 1000000;

    setCPUAffinity(0);
    benchmark(num_threads, num_orders);

    return 0;
}

