use std::collections::VecDeque;
use std::time::Duration;
use std::sync::{Arc, Mutex};
use std::net::{TcpStream, TcpListener};
use std::thread;
use std::fs::File;
use std::io::{BufReader, BufWriter};
use std::os::unix::prelude::OsRcOs;
use std::os::unix::fs::FileExt;

#[derive(Debug)]
struct TelemetryMessage {
    id: String,
    data: String,
    timestamp: String,
}

#[derive(Debug)]
struct TelemetryLogEntry {
    id: String,
    data: String,
    timestamp: String,
}

#[derive(Debug)]
struct TelemetryLog {
    entries: Vec<TelemetryLogEntry>,
}

impl TelemetryLog {
    fn new() -> Self {
        TelemetryLog { entries: Vec::new() }
    }

    fn append(&mut self, entry: TelemetryLogEntry) {
        self.entries.push(entry);
    }

    fn save(&self) {
        let file = File::create("telemetry_log.log").unwrap();
        let writer = BufWriter::new(file);
        for entry in &self.entries {
            writeln!(writer, "{} {}", entry.id, entry.data).unwrap();
        }
    }
}

struct TelemetryService {
    listener: TcpListener,
    log: Arc<Mutex<TelemetryLog>>,
    is_connected: bool,
    reconnection_attempts: usize,
}

impl TelemetryService {
    fn new() -> Self {
        let listener = TcpListener::bind("0.0.0.0:42423").unwrap();
        TelemetryService {
            listener,
            log: Arc::new(Mutex::new(TelemetryLog::new())),
            is_connected: false,
            reconnection_attempts: 0,
        }
    }

    fn handle_connection(&mut self, stream: TcpStream) {
        let mut buffer = [0; 1024];
        let mut reader = BufReader::new(stream);
        let mut writer = BufWriter::new(stream);

        let mut log = self.log.lock().unwrap();
        let mut entries = VecDeque::new();

        loop {
            let bytes_read = reader.read(&mut buffer).unwrap();
            if bytes_read == 0 {
                break;
            }

            let message = String::from_utf8_lossy(&buffer[..bytes_read]);
            let parts: Vec<&str> = message.split_whitespace().collect();

            if parts.len() < 2 {
                continue;
            }

            let id = parts[0];
            let data = parts[1..].join(" ");

            let timestamp = format!("{}", std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs());

            let entry = TelemetryLogEntry {
                id: id.to_string(),
                data: data.to_string(),
                timestamp: timestamp,
            };

            entries.push_back(entry);

            log.append(entry);

            if let Err(e) = writer.write_all(b"") {
                eprintln!("Failed to write to stream: {}", e);
                break;
            }
        }

        if !entries.is_empty() {
            log.save();
        }
    }

    fn reconnection(&mut self) {
        self.reconnection_attempts += 1;
        if self.reconnection_attempts > 3 {
            return;
        }

        let stream = self.listener.accept().unwrap();
        thread::spawn(move || {
            let mut service = Self::new();
            service.handle_connection(stream);
        });
    }
}

fn main() {
    let service = TelemetryService::new();
    let mut thread_handle = thread::spawn(move || {
        loop {
            service.reconnection();
            std::thread::sleep(Duration::from_secs(10));
        }
    });

    let mut thread_handle.join().unwrap();
}
