  ngOnDestroy() {
    if (this.chart) {
      this.chart.destroy();
    }
  }

  initChart() {
    this.chart = new Chart(this.chartContainer.nativeElement, {
      type: 'bar',
      data: {
        labels: ['Revenue', 'Expenses', 'Profit'],
        datasets: [{
          label: 'Financial Metrics',
          data: [12000, 8000, 4000],
          backgroundColor: ['#4CAF50', '#f44336', '#2196F3']
        }]
      },
      options: {
        responsive: true,
        plugins: {
          tooltip: {
            mode: 'index',
            intersect: false
          },
          contextMenu: {
            mode: 'custom',
            callbacks: {
              itemClicked: (context, index) => {
                this.tooltip = context;
                return true;
              }
            }
          }
        },
        layout: {
          padding: {
            left: 10,
            right: 10,
            top: 10,
            bottom: 10
          }
        },
        dragAndDrop: true,
        dragStart: (e) => {
          this.dragStartX = e.clientX;
          this.dragStartY = e.clientY;
          this.isDragging = true;
        },
        dragEnd: () => {
          this.isDragging = false;
        },
        resize: (e) => {
          this.isResizing = true;
        },
        resizeEnd: () => {
          this.isResizing = false;
        },
        hover: (e) => {
          this.tooltip = e;
        }
      }
    });
  }

  handleNetworkStatus() {
    // Simulate network status check
    this.networkStatus = Math.random() < 0.5 ? 'online' : 'offline';
  }

  showOfflineBanner() {
    alert('Offline mode is active. Please check your internet connection.');
  }

  showSkeletonLoader() {
    // Simulate skeleton loader
    setTimeout(() => {
      this.chart.data.datasets[0].data = [12000, 8000, 4000];
      this.chart.update();
    }, 500);
  }
}
